import React, { useState, useMemo, useCallback } from 'react';
import type {
  CustomerMatchGroup,
  CustomerMatchResult,
  CustomerMatchCandidate,
  CustomerResolution,
} from '../../../../../services/kt/bankStatementImportModels';
import styles from './CustomerGroupMatch.module.css';

interface CustomerGroupMatchProps {
  matchResult: CustomerMatchResult;
  onConfirm: (resolutions: CustomerResolution[]) => void;
  onBack: () => void;
}

const CustomerGroupMatch: React.FC<CustomerGroupMatchProps> = ({
  matchResult,
  onConfirm,
  onBack,
}) => {
  // Track which groups have been manually confirmed by the user
  const [resolvedGroups, setResolvedGroups] = useState<Record<string, { selectedCustomerId: string | null }>>({});
  const [confirmGroup, setConfirmGroup] = useState<CustomerMatchGroup | null>(null);

  // ── Filter tabs ──────────────────────────────────────
  const filterTabs = useMemo(() => {
    const autoGroups = matchResult.groups.filter(g => g.exactMatch !== null);
    const needsConfirm = matchResult.groups.filter(g => g.exactMatch === null);
    return [
      { key: 'all' as const, label: `Tất cả (${matchResult.groups.length})` },
      { key: 'auto' as const, label: `Tự động (${autoGroups.length})`, badge: autoGroups.length },
      { key: 'needs_confirm' as const, label: `Cần xác nhận (${needsConfirm.length})`, badge: needsConfirm.length },
    ];
  }, [matchResult]);

  const [activeFilter, setActiveFilter] = useState<'all' | 'auto' | 'needs_confirm'>('all');

  const filteredGroups = useMemo(() => {
    switch (activeFilter) {
      case 'auto': return matchResult.groups.filter(g => g.exactMatch !== null);
      case 'needs_confirm': return matchResult.groups.filter(g => g.exactMatch === null);
      default: return matchResult.groups;
    }
  }, [matchResult, activeFilter]);

  // Groups that still need user confirmation
  const unresolvedGroups = useMemo(
    () => matchResult.groups.filter(g => g.exactMatch === null && !resolvedGroups[g.groupKey]),
    [matchResult, resolvedGroups],
  );

  const allResolved = unresolvedGroups.length === 0;

  // ── Handle confirm from modal ────────────────────────
  const handleModalConfirm = useCallback((groupKey: string, selectedCustomerId: string | null) => {
    setResolvedGroups(prev => ({ ...prev, [groupKey]: { selectedCustomerId } }));
    setConfirmGroup(null);
  }, []);

  // ── Build resolutions and proceed ────────────────────
  const handleProceed = useCallback(() => {
    const resolutions: CustomerResolution[] = [];
    for (const group of matchResult.groups) {
      const resolved = resolvedGroups[group.groupKey];
      const selectedId = resolved?.selectedCustomerId ?? group.exactMatch?.customerId ?? null;
      for (const rowIdx of group.rowIndices) {
        resolutions.push({
          rowIndex: rowIdx,
          existingCustomerId: selectedId ?? undefined,
          autoApplyRowIndices: [rowIdx],
        });
      }
    }
    onConfirm(resolutions);
  }, [matchResult, resolvedGroups, onConfirm]);

  // ── Score color ──────────────────────────────────────
  const scoreColor = (score: number): string => {
    if (score >= 100) return '#22c55e';
    if (score >= 80) return '#eab308';
    return '#ef4444';
  };

  const confirmButtonDisabled = !allResolved;

  return (
    <div className={styles.container}>
      <h3 className={styles.title}>Xác nhận đối tượng khách hàng</h3>
      <p className={styles.subtitle}>
        Hệ thống đã gom nhóm theo đơn vị thụ hưởng và tài khoản. 
        Các nhóm tự động khớp hiển thị với khung xanh, nhóm cần xác nhận hiển thị với khung cam.
      </p>

      {/* Summary cards */}
      <div className={styles.summaryCards}>
        <div className={styles.card}>
          <span className={styles.cardValue}>{matchResult.autoMatchedCount}</span>
          <span className={styles.cardLabel}>Tự động khớp</span>
        </div>
        <div className={styles.card}>
          <span className={styles.cardValue}>{matchResult.needsConfirmCount}</span>
          <span className={styles.cardLabel}>Cần xác nhận</span>
        </div>
        <div className={styles.card}>
          <span className={styles.cardValue}>{matchResult.totalRowCount}</span>
          <span className={styles.cardLabel}>Tổng dòng</span>
        </div>
        <div className={`${styles.card} ${allResolved ? styles.cardSuccess : styles.cardWarning}`}>
          <span className={styles.cardValue}>{unresolvedGroups.length}</span>
          <span className={styles.cardLabel}>Chưa xử lý</span>
        </div>
      </div>

      {/* Filter tabs */}
      <div className={styles.filterTabs}>
        {filterTabs.map(tab => (
          <button
            key={tab.key}
            className={`${styles.filterTab} ${activeFilter === tab.key ? styles.filterTabActive : ''}`}
            onClick={() => setActiveFilter(tab.key)}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {/* Group list */}
      <div className={styles.groupList}>
        {filteredGroups.map(group => {
          const isAutoMatched = group.exactMatch !== null;
          const isResolved = resolvedGroups[group.groupKey] !== undefined;
          const bgClass = isAutoMatched
            ? styles.groupAuto
            : isResolved
              ? styles.groupResolved
              : styles.groupNeedsConfirm;

          return (
            <div key={group.groupKey} className={`${styles.groupCard} ${bgClass}`}>
              <div className={styles.groupHeader}>
                <div className={styles.groupInfo}>
                  <strong className={styles.groupName}>{group.displayCounterparty}</strong>
                  {group.displayBankAccount && (
                    <span className={styles.groupAccount}>TK: {group.displayBankAccount}</span>
                  )}
                </div>
                <div className={styles.groupMeta}>
                  <span className={styles.groupRowCount}>{group.rowCount} dòng</span>
                  {!isAutoMatched && !isResolved && (
                    <button
                      className={styles.confirmBtn}
                      onClick={() => setConfirmGroup(group)}
                    >
                      Xác nhận KH
                    </button>
                  )}
                  {isAutoMatched && (
                    <span className={styles.autoBadge}>Đã tự động khớp</span>
                  )}
                  {isResolved && (
                    <span className={styles.manualBadge}>Đã xác nhận</span>
                  )}
                </div>
              </div>

              {/* Auto-matched customer info */}
              {(isAutoMatched || isResolved) && (
                <div className={styles.matchInfo}>
                  {isAutoMatched && group.exactMatch && (
                    <div className={styles.matchDetails}>
                      <span className={styles.matchCode}>Mã: {group.exactMatch.code}</span>
                      <span className={styles.matchName}> - {group.exactMatch.name}</span>
                      <span
                        className={styles.matchScore}
                        style={{ color: scoreColor(group.exactMatch.matchScore) }}
                      >
                        ({group.exactMatch.matchScore}%) 
                        {group.exactMatch.matchMethod === 'exact_name' && '- Khớp tên'}
                        {group.exactMatch.matchMethod === 'exact_code' && '- Khớp mã'}
                      </span>
                    </div>
                  )}
                  {isResolved && resolvedGroups[group.groupKey]?.selectedCustomerId && (
                    <span className={styles.matchDetails}>
                      Đã chọn KH ID: {resolvedGroups[group.groupKey].selectedCustomerId}
                    </span>
                  )}
                </div>
              )}

              {/* Candidates list (needs confirm) */}
              {!isAutoMatched && !isResolved && group.candidates.length > 0 && (
                <div className={styles.candidatesPreview}>
                  <span className={styles.candidatesTitle}>Gợi ý:</span>
                  {group.candidates.slice(0, 3).map(c => (
                    <span key={c.customerId} className={styles.candidateChip}
                      style={{ borderColor: scoreColor(c.matchScore) }}
                    >
                      {c.code} - {c.name} ({c.matchScore}%)
                    </span>
                  ))}
                  {group.candidates.length > 3 && (
                    <span className={styles.moreCandidates}>
                      +{group.candidates.length - 3} khác
                    </span>
                  )}
                </div>
              )}

              {/* No candidates — needs new customer */}
              {!isAutoMatched && !isResolved && group.candidates.length === 0 && (
                <div className={styles.noCandidates}>
                  <span className={styles.noCandText}>Không tìm thấy khách hàng phù hợp — cần tạo mới</span>
                </div>
              )}
            </div>
          );
        })}

        {filteredGroups.length === 0 && (
          <div className={styles.empty}>Không có nhóm nào.</div>
        )}
      </div>

      {/* Confirmation modal */}
      {confirmGroup && (
        <GroupConfirmModal
          group={confirmGroup}
          onConfirm={(selectedId) => handleModalConfirm(confirmGroup.groupKey, selectedId)}
          onClose={() => setConfirmGroup(null)}
        />
      )}

      {/* Action buttons */}
      <div className={styles.actions}>
        <button className={styles.backBtn} onClick={onBack}>Quay lại</button>
        <button
          className={styles.nextBtn}
          disabled={confirmButtonDisabled}
          onClick={handleProceed}
          title={confirmButtonDisabled ? 'Vui lòng xác nhận tất cả nhóm trước khi tiếp tục' : undefined}
        >
          {confirmButtonDisabled
            ? `Còn ${unresolvedGroups.length} nhóm chưa xác nhận`
            : `Tiếp theo → Phân tích chi tiết (${matchResult.groups.length} nhóm)`}
        </button>
      </div>
    </div>
  );
};

// ── Inline confirm modal ─────────────────────────────────────────────────

interface GroupConfirmModalProps {
  group: CustomerMatchGroup;
  onConfirm: (selectedCustomerId: string | null) => void;
  onClose: () => void;
}

const GroupConfirmModal: React.FC<GroupConfirmModalProps> = ({ group, onConfirm, onClose }) => {
  const [selectedCandidateId, setSelectedCandidateId] = useState<string | null>(null);
  const [mode, setMode] = useState<'select_existing' | 'create_new'>('select_existing');

  const scoreColor = (score: number): string => {
    if (score >= 100) return '#22c55e';
    if (score >= 80) return '#eab308';
    return '#ef4444';
  };

  return (
    <div className={styles.modalOverlay} onClick={onClose}>
      <div className={styles.modalContent} onClick={e => e.stopPropagation()}>
        <div className={styles.modalHeader}>
          <h4>Xác nhận khách hàng</h4>
          <button className={styles.modalClose} onClick={onClose}>×</button>
        </div>

        <div className={styles.modalBody}>
          <div className={styles.modalInfo}>
            <p><strong>Đơn vị thụ hưởng:</strong> {group.displayCounterparty}</p>
            {group.displayBankAccount && (
              <p><strong>Tài khoản:</strong> {group.displayBankAccount}</p>
            )}
            <p><strong>Số dòng:</strong> {group.rowCount}</p>
          </div>

          {/* Mode toggle */}
          <div className={styles.modeToggle}>
            <button
              className={`${styles.modeBtn} ${mode === 'select_existing' ? styles.modeBtnActive : ''}`}
              onClick={() => setMode('select_existing')}
            >
              Chọn KH đã có
            </button>
            <button
              className={`${styles.modeBtn} ${mode === 'create_new' ? styles.modeBtnActive : ''}`}
              onClick={() => setMode('create_new')}
            >
              Tạo KH mới
            </button>
          </div>

          {mode === 'select_existing' && group.candidates.length > 0 && (
            <div className={styles.candidateList}>
              {group.candidates.map(c => (
                <label
                  key={c.customerId}
                  className={`${styles.candidateRow} ${selectedCandidateId === c.customerId ? styles.candidateSelected : ''}`}
                >
                  <input
                    type="radio"
                    name="candidate"
                    checked={selectedCandidateId === c.customerId}
                    onChange={() => setSelectedCandidateId(c.customerId)}
                  />
                  <div className={styles.candidateInfo}>
                    <div className={styles.candidatePrimary}>
                      <span className={styles.candidateCode}>{c.code}</span>
                      <span className={styles.candidateName}>{c.name}</span>
                    </div>
                    <div className={styles.candidateMeta}>
                      {c.phone && <span>📞 {c.phone}</span>}
                      {c.taxCode && <span>📋 {c.taxCode}</span>}
                    </div>
                  </div>
                  <span
                    className={styles.candidateScore}
                    style={{ color: scoreColor(c.matchScore), fontWeight: 600 }}
                  >
                    {c.matchScore}%
                  </span>
                </label>
              ))}
            </div>
          )}

          {mode === 'select_existing' && group.candidates.length === 0 && (
            <div className={styles.noMatchWarning}>
              Không tìm thấy khách hàng nào trong hệ thống. Vui lòng chọn "Tạo KH mới".
            </div>
          )}

          {mode === 'create_new' && (
            <div className={styles.createNewInfo}>
              <p>Khách hàng mới sẽ được tạo với thông tin từ sao kê:</p>
              <ul>
                <li>Tên: <strong>{group.displayCounterparty}</strong></li>
                {group.displayBankAccount && <li>Tài khoản: {group.displayBankAccount}</li>}
                <li>Số dòng: {group.rowCount}</li>
              </ul>
              <p className={styles.note}>
                Bạn sẽ có thể điều chỉnh chi tiết (mã, nhóm, ...) ở bước sau.
              </p>
            </div>
          )}
        </div>

        <div className={styles.modalActions}>
          <button className={styles.modalCancelBtn} onClick={onClose}>Huỷ</button>
          <button
            className={styles.modalConfirmBtn}
            disabled={mode === 'select_existing' && !selectedCandidateId}
            onClick={() => {
              if (mode === 'select_existing' && selectedCandidateId) {
                onConfirm(selectedCandidateId);
              } else if (mode === 'create_new') {
                onConfirm(null); // null = create new
              }
            }}
          >
            {mode === 'select_existing' ? 'Xác nhận KH này' : 'Tạo KH mới'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default CustomerGroupMatch;
